import { useState } from "react";

import API from "../services/api";

function BudgetForm() {

  const [budget,
    setBudget] =
    useState("");



  const handleBudget =
    async (e) => {

    e.preventDefault();

    try {

      const token =
        localStorage.getItem(
          "token"
        );

      await API.post(
        "/budget/set",
        {
          monthlyBudget:
            budget,
        },
        {
          headers: {
            Authorization:
              `Bearer ${token}`,
          },
        }
      );

      alert(
        "Budget Saved"
      );

    } catch (error) {

      alert(
        "Budget Save Failed"
      );

    }
  };





  return (

    <form
      onSubmit={handleBudget}
      className="
      bg-white
      rounded-xl
      shadow-lg
      p-6
      mt-10
    "
    >

      <h2
        className="
        text-2xl
        font-bold
        mb-4
      "
      >
        Monthly Budget
      </h2>

      <input
        type="number"
        placeholder="Enter Budget"
        value={budget}
        onChange={(e) =>
          setBudget(
            e.target.value
          )
        }
        className="
        w-full
        border
        p-3
        rounded-lg
        mb-4
      "
      />

      <button
        type="submit"
        className="
        bg-green-600
        text-white
        px-6
        py-3
        rounded-lg
      "
      >
        Save Budget
      </button>

    </form>
  );
}

export default BudgetForm;
